/** A layer that renders array (lens) data as an alpha-blended image. Its rendering is described entirely by the composable render graph; its placement, entirely by the coordinate graph. */
export type ImageLayer = Layer & {
  __typename?: 'ImageLayer';
  blending: Blending;
  id: Scalars['ID']['output'];
  kind: LayerKind;
  lens: Lens;
  /** Per pyramid level, the path from that level's voxel grid to this scene's WORLD system. What a multiscale renderer consumes directly: pick a level by zoom and use its path -- every level stars into the same intrinsic system, so the registration tail is shared. A level's path is null when the dataset is not registered into the scene */
  levelPaths: Array<LevelPlacement>;
  opacity: Scalars['Float']['output'];
  order: Scalars['Int']['output'];
  /** The path of transformation edges from this layer's source coordinate system to its scene's WORLD system. A layer belongs to exactly one scene, so this is the one 'to world' question with a single right answer -- the path uses the layer's dataset facts plus this scene's membership edges, never another scene's registration. Null when the layer is unregistered or has no source system; empty when the source already is the world system. The server returns the edges; composing them (inverting flagged steps) stays the client's job */
  pathToWorld?: Maybe<Array<PlacementStep>>;
  /** The composable in-layer render graph, if this layer defines one */
  renderGraph?: Maybe<LayerRenderGraph>;
  scene: Scene;
  status: PlacementStatus;
  /** How much this layer's placement is actually known. A registration the server assumed (the identity on the axes the dataset and the world share, created when the layer was placed) stays UNKNOWN -- badge it. MANUAL and VALIDATED are what a registration someone actually made or checked looks like */
  validity: PlacementValidity;
  visible: Scalars['Boolean']['output'];
};

