/** Input for creating a region of interest (ROI) on an image */
export type RoiInput = {
  /** The image this ROI belongs to */
  image: Scalars['ID']['input'];
  /** The type/kind of ROI */
  kind: RoiKind;
  /** The vector coordinates defining the ROI */
  vectors: Array<Scalars['FiveDVector']['input']>;
};

/** The geometric kind of a region of interest (ROI), defining how its vectors are interpreted. */
export enum RoiKind {
  /** A three-dimensional cuboid spanning the spatial axes (XYZ). */
  Cube = 'CUBE',
  /** An elliptical region in the XY plane. */
  Ellipsis = 'ELLIPSIS',
  /** A single frame of the image, e.g. one timepoint. */
  Frame = 'FRAME',
  /** A four-dimensional region spanning space and time (XYZT). */
  Hypercube = 'HYPERCUBE',
  /** A straight line between two points. */
  Line = 'LINE',
  /** An open path defined by a sequence of connected points. */
  Path = 'PATH',
  /** A single point. */
  Point = 'POINT',
  /** A closed polygon defined by a sequence of vertices. */
  Polygon = 'POLYGON',
  /** An axis-aligned rectangle in the XY plane. */
  Rectangle = 'RECTANGLE',
  /** A single slice of the image, e.g. one Z plane. */
  Slice = 'SLICE',
  /** A cuboid extended along the channel axis (XYZC). */
  SpectralCube = 'SPECTRAL_CUBE',
  /** A five-dimensional region spanning space, time and channels (XYZTC). */
  SpectralHypercube = 'SPECTRAL_HYPERCUBE',
  /** A rectangle extended along the channel axis (XYC). */
  SpectralRectangle = 'SPECTRAL_RECTANGLE',
  /** A cuboid extended along the time axis (XYZT). */
  TemporalCube = 'TEMPORAL_CUBE',
  /** A rectangle extended along the time axis (XYT). */
  TemporalRectangle = 'TEMPORAL_RECTANGLE'
}

export enum RoiKindChoices {
  Cube = 'CUBE',
  Ellipsis = 'ELLIPSIS',
  Frame = 'FRAME',
  Hypercube = 'HYPERCUBE',
  Line = 'LINE',
  Path = 'PATH',
  Point = 'POINT',
  Polygon = 'POLYGON',
  Rectangle = 'RECTANGLE',
  Slice = 'SLICE',
  SpectralCube = 'SPECTRAL_CUBE',
  SpectralHypercube = 'SPECTRAL_HYPERCUBE',
  SpectralRectangle = 'SPECTRAL_RECTANGLE',
  TemporalCube = 'TEMPORAL_CUBE',
  TemporalRectangle = 'TEMPORAL_RECTANGLE',
  Unknown = 'UNKNOWN'
}

/** A discrete coordinate an ROI is pinned to, e.g. a timepoint or a channel */
export type RoiSelector = {
  __typename?: 'RoiSelector';
  /** The name of the discrete axis, e.g. 't' or 'c' */
  axis: Scalars['String']['output'];
  /** The coordinate along that axis */
  index: Scalars['Int']['output'];
};

/** A rotation, given as an orthonormal matrix */
export type RotationTransformation = Transformation & {
  __typename?: 'RotationTransformation';
  /** The rotation matrix */
  affine: Array<Array<Scalars['Float']['output']>>;
  id: Scalars['ID']['output'];
  input?: Maybe<CoordinateSystem>;
  /** The names of the input axes this edge's parameters are ordered by. `scale`, `translation` and the columns of `affine` follow this order -- which is the input system's axis order, NOT the reading layer's dims, and the two differ often enough that indexing the arrays against dims silently misplaces them. A BY_DIMENSION edge names only the subset of axes it acts on; the axes it does not name are the ones it leaves untouched */
  inputAxes: Array<Scalars['String']['output']>;
  kind: TransformKind;
  name?: Maybe<Scalars['String']['output']>;
  output?: Maybe<CoordinateSystem>;
  /** The names of the output axes this edge produces. For a rank-changing BY_DIMENSION edge (placing a (c,y,x) dataset into a (t,z,y,x) world) this is the subset it maps onto; the world's other axes are untouched */
  outputAxes: Array<Scalars['String']['output']>;
  version: Scalars['Int']['output'];
};

export type RowFilter = {
  clause?: InputMaybe<Scalars['String']['input']>;
};

/** The sample */
export type SampleElement = OpticalElement & {
  __typename?: 'SampleElement';
  id: Scalars['ID']['output'];
  kind: ElementKind;
  label: Scalars['String']['output'];
  manufacturer?: Maybe<Scalars['String']['output']>;
  model?: Maybe<Scalars['String']['output']>;
  /** List of ports on the element */
  ports: Array<LightPort>;
  /** 3D pose of the element */
  pose?: Maybe<Pose3D>;
  serialNumber?: Maybe<Scalars['String']['output']>;
};

/** Input type for one pyramid level: the array backing it. Its scale is derived from its actual shape, never supplied */
export type ScaleInput = {
  /** The array-like object to create the image from */
  array: Scalars['ArrayLike']['input'];
  level: Scalars['Int']['input'];
  /** The method used to create the scale, e.g. 'nearest', 'bilinear', 'bicubic'. Recorded as provenance on the level's transformation */
  scaleMethod?: InputMaybe<Scalars['String']['input']>;
};

/** A per-axis multiplication, with one entry per input axis */
export type ScaleTransformation = Transformation & {
  __typename?: 'ScaleTransformation';
  id: Scalars['ID']['output'];
  input?: Maybe<CoordinateSystem>;
  /** The names of the input axes this edge's parameters are ordered by. `scale`, `translation` and the columns of `affine` follow this order -- which is the input system's axis order, NOT the reading layer's dims, and the two differ often enough that indexing the arrays against dims silently misplaces them. A BY_DIMENSION edge names only the subset of axes it acts on; the axes it does not name are the ones it leaves untouched */
  inputAxes: Array<Scalars['String']['output']>;
  kind: TransformKind;
  name?: Maybe<Scalars['String']['output']>;
  output?: Maybe<CoordinateSystem>;
  /** The names of the output axes this edge produces. For a rank-changing BY_DIMENSION edge (placing a (c,y,x) dataset into a (t,z,y,x) world) this is the subset it maps onto; the world's other axes are untouched */
  outputAxes: Array<Scalars['String']['output']>;
  /** The per-axis scale factors, in the axis order of the input system, expressed in the units of the output system's axes (dimensionless between pixel systems, e.g. within a pyramid). Absolute, not relative to another level */
  scale: Array<Scalars['Float']['output']>;
  version: Scalars['Int']['output'];
};

/** A view linking an image to a downscaled version of another image. Scale views form the levels of a multiscale pyramid: the parent is the full-resolution image and the scale factors give the downsampling per dimension. */
export type ScaleView = View & {
  __typename?: 'ScaleView';
  /** The accessor */
  accessor: Array<Scalars['String']['output']>;
  cMax?: Maybe<Scalars['Int']['output']>;
  cMin?: Maybe<Scalars['Int']['output']>;
  /** All views of this image */
  congruentViews: Array<View>;
  id: Scalars['ID']['output'];
  image: Image;
  isGlobal: Scalars['Boolean']['output'];
  parent: Image;
  scaleC: Scalars['Float']['output'];
  scaleT: Scalars['Float']['output'];
  scaleX: Scalars['Float']['output'];
  scaleY: Scalars['Float']['output'];
  scaleZ: Scalars['Float']['output'];
  tMax?: Maybe<Scalars['Int']['output']>;
  tMin?: Maybe<Scalars['Int']['output']>;
  xMax?: Maybe<Scalars['Int']['output']>;
  xMin?: Maybe<Scalars['Int']['output']>;
  yMax?: Maybe<Scalars['Int']['output']>;
  yMin?: Maybe<Scalars['Int']['output']>;
  zMax?: Maybe<Scalars['Int']['output']>;
  zMin?: Maybe<Scalars['Int']['output']>;
};


/** A view linking an image to a downscaled version of another image. Scale views form the levels of a multiscale pyramid: the parent is the full-resolution image and the scale factors give the downsampling per dimension. */
export type ScaleViewCongruentViewsArgs = {
  filters?: InputMaybe<ViewFilter>;
  types?: InputMaybe<Array<ViewKind>>;
};

/** The axis traversal order of a continuous scan, i.e. the order in which rows, columns and slices are acquired. */
export enum ScanDirection {
  /** Scan columns first, then rows, then slices (Column -> Row -> Slice). */
  ColumnRowSlice = 'COLUMN_ROW_SLICE',
  /** Scan columns, then rows, then slices, reversing direction on alternate lines (Column -> Row -> Slice, snake). */
  ColumnRowSliceSnake = 'COLUMN_ROW_SLICE_SNAKE',
  /** Scan rows first, then columns, then slices (Row -> Column -> Slice). */
  RowColumnSlice = 'ROW_COLUMN_SLICE',
  /** Scan rows, then columns, then slices, reversing direction on alternate lines (Row -> Column -> Slice, snake). */
  RowColumnSliceSnake = 'ROW_COLUMN_SLICE_SNAKE',
  /** Scan slices first, then rows, then columns (Slice -> Row -> Column). */
  SliceRowColumn = 'SLICE_ROW_COLUMN',
  /** Scan slices, then rows, then columns, reversing direction on alternate lines (Slice -> Row -> Column, snake). */
  SliceRowColumnSnake = 'SLICE_ROW_COLUMN_SNAKE'
}

/** A composition of layers over a shared WORLD coordinate system. The scene carries no units of its own -- they are per-axis, on the axes of its world system */
export type Scene = {
  __typename?: 'Scene';
  /** Every coordinate system reachable in this scene: its world system plus those its transformation edges touch */
  coordinateSystems: Array<CoordinateSystem>;
  /** The transformation edges belonging to this scene, e.g. the registrations placing each layer's dataset into the world system. This membership set is what `layers.pathToWorld` searches; composing the matrices stays the client's job */
  coordinateTransformations: Array<Transformation>;
  /** The wall-clock instant the world system's time axis has its origin at: `wall_clock = epoch + t * unit`. Null when the scene's acquisition time is unknown -- the time axis is still a perfectly composable relative coordinate without it */
  epoch?: Maybe<Scalars['DateTime']['output']>;
  id: Scalars['ID']['output'];
  /** The layers placed in this scene (a heterogeneous list of layer kinds) */
  layers: Array<Layer>;
  name: Scalars['String']['output'];
  /** The ROIs drawn in a coordinate system this scene can reach. Reachability, not containment: an ROI belongs to a coordinate system, and survives the scene's deletion */
  rois: Array<DataRoi>;
  /** The scene's shared WORLD coordinate system, into which each of its layers is registered */
  worldCoordinateSystem?: Maybe<CoordinateSystem>;
};


/** A composition of layers over a shared WORLD coordinate system. The scene carries no units of its own -- they are per-axis, on the axes of its world system */
export type SceneLayersArgs = {
  filters?: InputMaybe<LayerFilter>;
  ordering?: Array<LayerOrder>;
  pagination?: InputMaybe<OffsetPaginationInput>;
};

export type SceneFilter = {
  AND?: InputMaybe<SceneFilter>;
  DISTINCT?: InputMaybe<Scalars['Boolean']['input']>;
  NOT?: InputMaybe<SceneFilter>;
  OR?: InputMaybe<SceneFilter>;
  blending?: InputMaybe<BlendingChoices>;
  id?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by list of IDs */
  ids?: InputMaybe<Array<Scalars['ID']['input']>>;
  name?: InputMaybe<StrFilterLookup>;
  /** Filter by the parent scene */
  parent?: InputMaybe<Scalars['ID']['input']>;
  /** Filter for scenes with (true) or without (false) a parent */
  parentless?: InputMaybe<Scalars['Boolean']['input']>;
  /** Search by name (case-insensitive substring) */
  search?: InputMaybe<Scalars['String']['input']>;
};

export type SceneOrder =
  { id: Ordering; name?: never; }
  |  { id?: never; name: Ordering; };

/** Input for adding or removing an edge from a scene's composition */
export type SceneTransformationInput = {
  scene: Scalars['ID']['input'];
  transformation: Scalars['ID']['input'];
};

export type Selector = {
  c?: InputMaybe<DimSelector>;
  t?: InputMaybe<DimSelector>;
  x?: InputMaybe<DimSelector>;
  y?: InputMaybe<DimSelector>;
  z?: InputMaybe<DimSelector>;
};

/** Input for pinning an ROI to a coordinate on a discrete axis, e.g. a timepoint or a channel */
export type SelectorInput = {
  axis: Scalars['String']['input'];
  index: Scalars['Int']['input'];
};

/** An ordered composition of child transformations, applied first to last */
export type SequenceTransformation = Transformation & {
  __typename?: 'SequenceTransformation';
  id: Scalars['ID']['output'];
  input?: Maybe<CoordinateSystem>;
  /** The names of the input axes this edge's parameters are ordered by. `scale`, `translation` and the columns of `affine` follow this order -- which is the input system's axis order, NOT the reading layer's dims, and the two differ often enough that indexing the arrays against dims silently misplaces them. A BY_DIMENSION edge names only the subset of axes it acts on; the axes it does not name are the ones it leaves untouched */
  inputAxes: Array<Scalars['String']['output']>;
  kind: TransformKind;
  name?: Maybe<Scalars['String']['output']>;
  output?: Maybe<CoordinateSystem>;
  /** The names of the output axes this edge produces. For a rank-changing BY_DIMENSION edge (placing a (c,y,x) dataset into a (t,z,y,x) world) this is the subset it maps onto; the world's other axes are untouched */
  outputAxes: Array<Scalars['String']['output']>;
  /** The child transformations, applied first to last. They omit their own input and output: the sequence supplies them */
  transformations: Array<Transformation>;
  version: Scalars['Int']['output'];
};

/** A layer that renders the vector geometry of a data ROI (polygons, boxes, ellipses, lines, paths), placed and styled in a scene. */
export type ShapeLayer = Layer & {
  __typename?: 'ShapeLayer';
  blending: Blending;
  dataRoi: DataRoi;
  fillColor?: Maybe<Array<Scalars['Int']['output']>>;
  filled: Scalars['Boolean']['output'];
  id: Scalars['ID']['output'];
  kind: LayerKind;
  opacity: Scalars['Float']['output'];
  order: Scalars['Int']['output'];
  /** The path of transformation edges from this layer's source coordinate system to its scene's WORLD system. A layer belongs to exactly one scene, so this is the one 'to world' question with a single right answer -- the path uses the layer's dataset facts plus this scene's membership edges, never another scene's registration. Null when the layer is unregistered or has no source system; empty when the source already is the world system. The server returns the edges; composing them (inverting flagged steps) stays the client's job */
  pathToWorld?: Maybe<Array<PlacementStep>>;
  scene: Scene;
  status: PlacementStatus;
  strokeColor?: Maybe<Array<Scalars['Int']['output']>>;
  strokeWidth?: Maybe<Scalars['Float']['output']>;
  /** How much this layer's placement is actually known. A registration the server assumed (the identity on the axes the dataset and the world share, created when the layer was placed) stays UNKNOWN -- badge it. MANUAL and VALIDATED are what a registration someone actually made or checked looks like */
  validity: PlacementValidity;
  visible: Scalars['Boolean']['output'];
};

/** A slice along a named dimension, with optional start, stop and step */
export type Slice = {
  __typename?: 'Slice';
  /** The key of the dimension, e.g. 'x', 'y', 'z', 'c', or 't' */
  dim: Scalars['String']['output'];
  /** The starting index of the slice, or None to start from the beginning */
  start?: Maybe<Scalars['Int']['output']>;
  /** The step size of the slice, or None to use the default step */
  step?: Maybe<Scalars['Int']['output']>;
  /** The stopping index of the slice, or None to go to the end */
  stop?: Maybe<Scalars['Int']['output']>;
};

/** Input type for a dimension descriptor, which specifies a key and a kind for a dimension */
export type SliceInput = {
  dim: Scalars['String']['input'];
  start?: InputMaybe<Scalars['Int']['input']>;
  step?: InputMaybe<Scalars['Int']['input']>;
  stop?: InputMaybe<Scalars['Int']['input']>;
};

